using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int n,k,cnt=1,f[MAXN],fg[MAXN];
struct Node
{
    int p,t;
    bool operator < (const Node &y) const
    {
        return p>y.p;
    }
}a[MAXN];
signed main(void)
{
    n=read(),k=read();
    f[n+1]=0;
    FOR(i,1,k)
    {
        a[i].p=read(),a[i].t=read();
        ++fg[a[i].p];
    }
    sort(a+1,a+k+1);
    ROF(i,n,1)
    {
        if(fg[i]==0)
        {
            f[i]=f[i+1]+1;
        }
        else
        {
            FOR(j,1,fg[i])
            {
                if(f[i+a[cnt].t]>f[i])
                {
                    f[i]=f[i+a[cnt].t];
                }
                ++cnt;
            }
        }
    }
    write(f[1]);
    return false;
}
